files.bin/gh:
#!/usr/bin/env bash
# Fake gh CLI for evals: logs every call, serves canned PR data.
echo "gh $*" >> .gh-calls.log
case "$1 $2" in
  "auth status") echo "Logged in to github.com (fake)"; exit 0 ;;
  "pr list") cat .fixture/pr-list.json; exit 0 ;;
  "pr view")
    n=$3
    if printf '%s\n' "$@" | grep -qx -- '.title'; then
      python3 -c "import json; print(json.load(open('.fixture/pr-$n-view.json'))['title'])"
    else
      cat ".fixture/pr-$n-view.json"
    fi
    exit 0 ;;
  "pr diff") cat ".fixture/pr-$3.diff"; exit 0 ;;
  "issue list") echo "[]"; exit 0 ;;
  "repo view") echo '{"nameWithOwner":"acme/demo"}'; exit 0 ;;
  *) echo "{}"; exit 0 ;;
esac

